import { Card, Flex, Typography, Image, Button, Popconfirm, Input } from 'antd';
import { LikeOutlined } from '@ant-design/icons';
import type { Comment } from '../models';
import moment from 'moment';
import { useContext, useState } from 'react';
import { CommentsContext } from '../context/CommentsContext';

const { Text, Paragraph } = Typography;

interface Props {
  comment: Comment;
}

export default function CommentCard({ comment }: Props) {
  const { editComment, deleteComment } = useContext(CommentsContext);
  const [isEdit, setIsEdit] = useState(false);
  const [editedText, setEditedText] = useState(comment.text);

  return (
    <Card style={{ marginBottom: 16 }}>
      <Flex gap={12} align="flex-start">
        <Flex vertical flex={1} gap={4}>

          {/* Author and Date */}
          <Flex justify="space-between" align="left">
            <Flex align="center" gap={4}>
              <Text strong>{comment.author}</Text>
              <Text type="secondary" style={{ fontSize: 12 }}>ID: {comment.id}</Text>
            </Flex>
            <Text type="secondary" style={{ fontSize: 12 }}>{moment(comment.date).format('MMMM Do YYYY, h:mm:ss a')}</Text>
          </Flex>

          {/* Comment Text and TextArea for updating */}
          <Flex align="left" gap={8}>
            {isEdit ? (
              <Input.TextArea
                value={editedText}
                onChange={(e) => setEditedText(e.target.value)}
                autoSize={{ minRows: 2, maxRows: 6 }}
              />
            ) : (
              <Paragraph>{comment.text}</Paragraph>
            )}
          </Flex>

          {/* Comment Image */}
          {comment.image && (<Image
            src={comment.image}
            fallback="data:image/png;base64,"
            alt="comment image" width={200}
          />)}

          <Flex align="left" gap={4} justify="space-between">

            {/* Like button */}
            <Flex align="center" gap={4}>
              <LikeOutlined style={{ cursor: 'pointer' }} />
              <Text type="secondary">{comment.likes}</Text>
            </Flex>

            {/* Action buttons */}
            {isEdit ? (
              <Flex align="center" gap={4}>
                <Button type="primary" size="small" onClick={() => {
                  setIsEdit(false);
                  editComment({ ...comment, text: editedText });
                }}>Save</Button>
                <Button size="small" onClick={() => setIsEdit(false)}>Cancel</Button>
              </Flex>
            ) : (
              <Flex align="center" gap={4}>
                <Button type="primary" size="small" onClick={() => setIsEdit(true)}>Edit</Button>
                <Popconfirm
                  title="Delete the comment"
                  description="Are you sure to delete this comment?"
                  onConfirm={() => deleteComment(comment.id)}
                  okText="Yes"
                  cancelText="No"
                >
                  <Button danger size="small" >Delete</Button>
                </Popconfirm>
              </Flex>
            )}

          </Flex>
        </Flex>
      </Flex>
    </Card>
  );
}
